#include<bits/stdc++.h>
using namespace std;
int hope[1001][1001],f[1001][1001],ans[1001];
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			scanf("%d",&hope[i][j]);
		} 
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			f[i][hope[i][j]]=1;
			if(hope[i][j]==i)
			{
				break;
			}
		} 
	}
	for(int k=1;k<=n;k++)
	{
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=n;j++)
			{
				f[i][j]|=f[i][k]&f[k][j];
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=n;j>=1;j--)
		{
			if(f[hope[i][j]][i])
			{
				ans[i]=hope[i][j];
			}
		}
		printf("%d\n",ans[i]);
	}
	return 0;
}
